#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ; 
}
const int N=1e5+10,M=2e5+10;struct Node{int a,b,c,ans,w;}q[N],b[N];int mx,n;
struct BITree
{
	int t[M],n;inline int lowbit(int a){return a&(-a);}
	inline void Add(int pos,int val){while(pos<=n)t[pos]+=val,pos+=lowbit(pos);}
	inline int query(int pos){int res=0;while(pos)res+=t[pos],pos-=lowbit(pos);return res;}
	inline void Init(int a,int *g=0){n=a;memset(t,0,sizeof(t));return;}
}g; int ans[M],Ans[M];inline bool cmp2(Node a,Node b){return (a.b^b.b)?(a.b<b.b):(a.c<b.c);}
inline bool cmp1(Node a,Node b){return (a.a^b.a)?(a.a<b.a):((a.b^b.b)?(a.b<b.b):(a.c<b.c));}
void cdq(int l,int r)
{
	if(l==r)return;int mid=(l+r)>>1;cdq(l,mid);cdq(mid+1,r);
	sort(q+l,q+mid+1,cmp2);sort(q+mid+1,q+r+1,cmp2);int i=l;
	rep(mid+1,r,j)
	{
		while(q[i].b<=q[j].b&&i<=mid)g.Add(q[i].c,q[i].w),++i;
		q[j].ans+=g.query(q[j].c);
	}
	rep(l,i-1,k)g.Add(q[k].c,-q[k].w);
}
int main()
{
	int qn=read(),mx=read();rep(1,qn,i)b[i].a=read(),b[i].b=read(),b[i].c=read();sort(b+1,b+qn+1,cmp1);g.Init(mx);
	int c=0;rep(1,qn,i){c++;if((b[i].a^b[i+1].a)||(b[i].b^b[i+1].b)||(b[i].c^b[i+1].c))q[++n]=b[i],q[n].w=c,c=0;}
	cdq(1,n);rep(1,n,i)Ans[q[i].ans+q[i].w-1]+=q[i].w;rep(0,qn-1,i)printf("%d\n",Ans[i]);return 0;
}
